import{_ as s,o as i,c as e,a2 as t}from"./chunks/framework.BWuWLRhz.js";const c=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),n={name:"guide/getting-started.md"};function r(h,a,p,l,o,k){return i(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This guide walks through the happy path from zero to a deployed PHP application: register a server, connect a project, add your config, point a domain at it, and deploy.</p><div class="tip custom-block"><p class="custom-block-title">Prerequisites</p><p>You need a VPS with SSH access (any provider works) and a git repository containing a PHP application. See <a href="/self-hosting/requirements">requirements</a> for the supported server baseline.</p></div><h2 id="_1-create-an-account-and-team" tabindex="-1">1. Create an account and team <a class="header-anchor" href="#_1-create-an-account-and-team" aria-label="Permalink to &quot;1. Create an account and team&quot;">​</a></h2><p>Sign up, then create (or join) a <a href="/app/teams">Team</a>. The team owns your projects, servers, and members. If you are inviting collaborators, assign them the Owner, Admin, or Member role as appropriate.</p><div class="tip custom-block"><p class="custom-block-title">Secure your account</p><p>Enable <a href="/app/two-factor">two-factor authentication</a> before adding servers or production projects.</p></div><h2 id="_2-register-a-server-and-run-setup" tabindex="-1">2. Register a server and run setup <a class="header-anchor" href="#_2-register-a-server-and-run-setup" aria-label="Permalink to &quot;2. Register a server and run setup&quot;">​</a></h2><p>Add your VPS under <a href="/self-hosting/servers">Servers</a> by providing its host and SSH credentials. Tragwerk then runs an automated setup job that connects over SSH and provisions Docker and the base stack on the machine — all from the UI.</p><p>Watch the setup progress until the server reports ready. Details on what the job does are in <a href="/self-hosting/server-setup">server setup</a> and <a href="/self-hosting/architecture-on-host">architecture on the host</a>.</p><h2 id="_3-create-a-project-pointing-at-a-git-repo" tabindex="-1">3. Create a project pointing at a git repo <a class="header-anchor" href="#_3-create-a-project-pointing-at-a-git-repo" aria-label="Permalink to &quot;3. Create a project pointing at a git repo&quot;">​</a></h2><p>Create a <a href="/app/projects">Project</a> and connect it to your git repository through an <a href="/app/integrations">integration</a>. The branch you push becomes an <a href="/app/environments">environment</a> automatically.</p><h2 id="_4-add-tragwerk-config-xml" tabindex="-1">4. Add <code>.tragwerk/config.xml</code> <a class="header-anchor" href="#_4-add-tragwerk-config-xml" aria-label="Permalink to &quot;4. Add \`.tragwerk/config.xml\`&quot;">​</a></h2><p>Tragwerk generates your entire Docker setup from one XML file committed at <code>.tragwerk/config.xml</code> in your repository. Here is a minimal example that defines a single PHP 8.5 application served from <code>public/</code> and routed on your default domain:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;?</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">xml</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> version</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1.0&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> encoding</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;UTF-8&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ?&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">project</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> xmlns:xsi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://www.w3.org/2001/XMLSchema-instance&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">         xsi:noNamespaceSchemaLocation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;schema.xsd?v1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">applications</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">application</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;app&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;php:8.5&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> root</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> root</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;public&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> passthru</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/index.php&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">application</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">applications</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">routes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">route</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> pattern</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://{default}&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> upstream</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;app:http&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">routes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">project</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>The <code>{default}</code> placeholder in the route resolves to the environment&#39;s domain. For the full set of options — <a href="/config/applications">applications</a>, <a href="/config/web">web</a>, <a href="/config/workers">workers</a>, <a href="/config/crons">crons</a>, <a href="/config/hooks">hooks</a>, <a href="/config/mounts">mounts</a>, <a href="/config/relationships">relationships</a>, <a href="/config/services">services</a>, and <a href="/config/routes">routes</a> — see the <a href="/config/overview">configuration overview</a> and <a href="/config/examples">examples</a>.</p><div class="info custom-block"><p class="custom-block-title">Add a backing service</p><p>To attach a database, declare it under <code>&lt;services&gt;</code> and bind it with a <code>&lt;relationship&gt;</code>. Connection details are injected as environment variables at runtime. See <a href="/config/services">Services</a> and <a href="/config/relationships">relationships</a>.</p></div><h2 id="_5-add-a-domain" tabindex="-1">5. Add a domain <a class="header-anchor" href="#_5-add-a-domain" aria-label="Permalink to &quot;5. Add a domain&quot;">​</a></h2><p>Attach a hostname to your environment under <a href="/app/domains">Domains</a> and point that hostname&#39;s DNS at your server. Traefik will request a Let&#39;s Encrypt certificate for it automatically, so the <code>https://</code> route just works.</p><h2 id="_6-push-to-deploy" tabindex="-1">6. Push to deploy <a class="header-anchor" href="#_6-push-to-deploy" aria-label="Permalink to &quot;6. Push to deploy&quot;">​</a></h2><p>Push your branch. The git webhook triggers a <a href="/app/deployments">deployment</a>: Tragwerk clones the repo, builds the Docker image from your generated config, and starts the containers. You can also trigger a <strong>redeploy</strong> from the environment page at any time.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .tragwerk/config.xml</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Add Tragwerk config&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><h2 id="_7-watch-the-live-deployment-log" tabindex="-1">7. Watch the live deployment log <a class="header-anchor" href="#_7-watch-the-live-deployment-log" aria-label="Permalink to &quot;7. Watch the live deployment log&quot;">​</a></h2><p>Open the environment&#39;s <a href="/app/deployments">deployment</a> view to follow the build and release in real time. Once it finishes, visit your domain to see the app running.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li>Manage runtime config with <a href="/app/variables">environment variables</a>.</li><li>Add background <a href="/app/workers">workers</a> and <a href="/app/cronjobs">cronjobs</a>.</li><li>Inspect <a href="/app/logs-containers">container logs</a> and <a href="/app/metrics">metrics</a>.</li><li>Pull private images using <a href="/app/registries-credentials">registry credentials</a>.</li></ul>`,25)])])}const g=s(n,[["render",r]]);export{c as __pageData,g as default};
